(window.webpackJsonp=window.webpackJsonp||[]).push([[307],{1586:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">A</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxSubarraySumCircular = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">A</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> N = A.length;\\n  <span class=\\"hljs-keyword\\">let</span> P = <span class=\\"hljs-built_in\\">Array</span>(<span class=\\"hljs-number\\">2</span>*N+<span class=\\"hljs-number\\">1</span>).fill(<span class=\\"hljs-number\\">0</span>)\\n  <span class=\\"hljs-keyword\\">for</span> (<span class=\\"hljs-keyword\\">let</span> i = <span class=\\"hljs-number\\">0</span>; i &lt; <span class=\\"hljs-number\\">2</span>*N; ++i)\\n    P[i+<span class=\\"hljs-number\\">1</span>] = P[i] + A[i % N];\\n  <span class=\\"hljs-keyword\\">let</span> ans = A[<span class=\\"hljs-number\\">0</span>];\\n  <span class=\\"hljs-keyword\\">let</span> stack = [<span class=\\"hljs-number\\">0</span>]\\n  <span class=\\"hljs-keyword\\">for</span> (<span class=\\"hljs-keyword\\">let</span> j = <span class=\\"hljs-number\\">1</span>; j &lt;= <span class=\\"hljs-number\\">2</span>*N; ++j) {\\n    <span class=\\"hljs-keyword\\">if</span> (stack[<span class=\\"hljs-number\\">0</span>] &lt; j-N)stack.shift()\\n    ans = <span class=\\"hljs-built_in\\">Math</span>.max(ans, P[j] - P[stack[<span class=\\"hljs-number\\">0</span>]]);\\n    <span class=\\"hljs-keyword\\">while</span> (stack.length&gt;<span class=\\"hljs-number\\">0</span> &amp;&amp; P[j] &lt;= P[stack[stack.length<span class=\\"hljs-number\\">-1</span>]]){\\n      stack.pop()\\n    }\\n    stack.push(j)\\n  }\\n\\n  <span class=\\"hljs-keyword\\">return</span> ans;\\n\\n};\\n</code></pre>\\n"],"titleSlug":"maximum-sum-circular-subarray","hasThinking":false,"content":"<p>\u7ed9\u5b9a\u4e00\u4e2a\u7531\u6574\u6570\u6570\u7ec4 <code>A</code>&nbsp;\u8868\u793a\u7684<strong>\u73af\u5f62\u6570\u7ec4 <code>C</code></strong>\uff0c\u6c42 <code><strong>C</strong></code>&nbsp;\u7684\u975e\u7a7a\u5b50\u6570\u7ec4\u7684\u6700\u5927\u53ef\u80fd\u548c\u3002</p>\\n\\n<p>\u5728\u6b64\u5904\uff0c<em>\u73af\u5f62\u6570\u7ec4</em>\u610f\u5473\u7740\u6570\u7ec4\u7684\u672b\u7aef\u5c06\u4f1a\u4e0e\u5f00\u5934\u76f8\u8fde\u5448\u73af\u72b6\u3002\uff08\u5f62\u5f0f\u4e0a\uff0c\u5f53<code>0 &lt;= i &lt; A.length</code>&nbsp;\u65f6&nbsp;<code>C[i] = A[i]</code>\uff0c\u4e14\u5f53&nbsp;<code>i &gt;= 0</code>&nbsp;\u65f6&nbsp;<code>C[i+A.length] = C[i]</code>\uff09</p>\\n\\n<p>\u6b64\u5916\uff0c\u5b50\u6570\u7ec4\u6700\u591a\u53ea\u80fd\u5305\u542b\u56fa\u5b9a\u7f13\u51b2\u533a <code>A</code>&nbsp;\u4e2d\u7684\u6bcf\u4e2a\u5143\u7d20\u4e00\u6b21\u3002\uff08\u5f62\u5f0f\u4e0a\uff0c\u5bf9\u4e8e\u5b50\u6570\u7ec4&nbsp;<code>C[i], C[i+1], ..., C[j]</code>\uff0c\u4e0d\u5b58\u5728&nbsp;<code>i &lt;= k1, k2 &lt;= j</code>&nbsp;\u5176\u4e2d&nbsp;<code>k1 % A.length&nbsp;= k2 % A.length</code>\uff09</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>[1,-2,3,-2]\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece\u5b50\u6570\u7ec4 [3] \u5f97\u5230\u6700\u5927\u548c 3\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>[5,-3,5]\\n<strong>\u8f93\u51fa\uff1a</strong>10\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece\u5b50\u6570\u7ec4 [5,5] \u5f97\u5230\u6700\u5927\u548c 5 + 5 = 10\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>[3,-1,2,-1]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece\u5b50\u6570\u7ec4 [2,-1,3] \u5f97\u5230\u6700\u5927\u548c 2 + (-1) + 3 = 4\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>[3,-2,2,-3]\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece\u5b50\u6570\u7ec4 [3] \u548c [3,-2,2] \u90fd\u53ef\u4ee5\u5f97\u5230\u6700\u5927\u548c 3\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>[-2,-3,-1]\\n<strong>\u8f93\u51fa\uff1a</strong>-1\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece\u5b50\u6570\u7ec4 [-1] \u5f97\u5230\u6700\u5927\u548c -1\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ol>\\n\\t<li><code>-30000 &lt;= A[i] &lt;= 30000</code></li>\\n\\t<li><code>1 &lt;= A.length &lt;= 30000</code></li>\\n</ol>\\n","title":"918. \u73af\u5f62\u5b50\u6570\u7ec4\u7684\u6700\u5927\u548c","relatedTags":["\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"918"}')}}]);